  // regular mouse wheel (or two-finger vertical swipe) scrolls tabs.
  useEffect(() => {
    const el = tabBarRef.current;
    if (!el) return;
    const onWheel = (ev: WheelEvent): void => {
      if (Math.abs(ev.deltaX) > Math.abs(ev.deltaY)) return; // already horizontal
      ev.preventDefault();
