            key={tab.id}
            role="tab"
            aria-selected={isActive}
            tabIndex={isActive ? 0 : -1}
            data-tab-id={tab.id}
            data-tab-index={idx}
            data-active={isActive ? 'true' : 'false'}
            data-drag-over={isDragOver ? 'true' : 'false'}
            draggable={Boolean(onReorder)}
            onClick={() => onActivate(tab.id)}
            onKeyDown={(e) => {
              if (e.key !== 'Enter' && e.key !== ' ') return;
              e.preventDefault();
              onActivate(tab.id);
            }}
            onDragStart={(e) => {
              if (!onReorder) return;
              setDragSrc(idx);
