}

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 2048, height: 1320 } });

  page.on('console', (msg) => {
    const txt = msg.text();
    if (txt.includes('[bim] rendering budget:')) budgetDebug.push(txt);
    if (txt.includes('[bim] rendering budget threshold exceeded:')) budgetWarn.push(txt);
  });

  await page.goto('http://127.0.0.1:2000/', { waitUntil: 'domcontentloaded', timeout: 60000 });
  await page.waitForSelector('[data-testid="app-shell"]', { timeout: 30000 });
  await page.waitForTimeout(3500);

  // Main front-left
  await clickTabByText(page, 'Main front-left');
  await page.screenshot({ path: stamp('01-main-front-left.png'), fullPage: false });

  // Rear/right axonometric
  await clickTabByText(page, 'Rear/right');
  await page.screenshot({ path: stamp('02-rear-right-axonometric.png'), fullPage: false });

  // Front elevation
  await clickTabByText(page, 'Front elevation');
  await page.screenshot({ path: stamp('03-front-elevation.png'), fullPage: false });

  // Roof court high axonometric
  await clickTabByText(page, 'Roof court high');
  await page.screenshot({ path: stamp('05-roof-court-high-axonometric.png'), fullPage: false });

  // Return to main and record currently selected element if any.
  await clickTabByText(page, 'Main front-left');
  await page.waitForTimeout(2500);

  const meta = await page.evaluate(() => {
    const selectedBadge = document.querySelector('[data-testid="statusbar-selection-count"]');
    const offlineBadge = document.querySelector('[data-testid="statusbar-connection"]');
    const errs = document.querySelector('[data-testid="statusbar-error-count"]');
    return {
      selectedText: selectedBadge ? selectedBadge.textContent : null,
      connectionText: offlineBadge ? offlineBadge.textContent : null,
      errorText: errs ? errs.textContent : null,
      tabLabels: Array.from(document.querySelectorAll('[data-testid^="tab-activate-"]')).map((el) => (el.textContent || '').trim()),
    };
  });

  const summary = {
    captures,
    renderingBudget: {
      debugLines: budgetDebug,
      warnLines: budgetWarn,
      latestDebugLine: budgetDebug[budgetDebug.length - 1] ?? null,
      latestWarnLine: budgetWarn[budgetWarn.length - 1] ?? null,
    },
    uiMeta: meta,
  };
  fs.writeFileSync(path.join(outDir, 'summary.json'), JSON.stringify(summary, null, 2));

  await browser.close();
  console.log(JSON.stringify(summary, null, 2));
})().catch((err) => {
  console.error(err);
  process.exit(1);
});
