const fs = require('fs');
const path = require('path');
const { chromium } = require('@playwright/test');

const outDir = path.resolve('packages/web/tmp/ux-next-wp05-20260513');
fs.mkdirSync(outDir, { recursive: true });

const captures = [];
const budgetDebug = [];
const budgetWarn = [];

const viewpoints = [
  { name: 'Target-house-3 primary front-right axonometric', shot: '01-main-front-left.png' },
  { name: 'Rear/right axonometric', shot: '02-rear-right-axonometric.png' },
  { name: 'Front elevation', shot: '03-front-elevation.png' },
  { name: 'Roof court high axonometric', shot: '05-roof-court-high-axonometric.png' },
];

function shotPath(file) {
  captures.push(file);
  return path.join(outDir, file);
}

async function openViewFromBrowser(page, name) {
  const row = page.getByText(name, { exact: true }).first();
  await row.waitFor({ state: 'visible', timeout: 20000 });
  await row.click();
  await page.waitForTimeout(1200);
}

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 2048, height: 1320 } });

  page.on('console', (msg) => {
    const txt = msg.text();
    if (txt.includes('[bim] rendering budget:')) budgetDebug.push(txt);
    if (txt.includes('[bim] rendering budget threshold exceeded:')) budgetWarn.push(txt);
  });

  await page.goto('http://127.0.0.1:2000/', { waitUntil: 'domcontentloaded', timeout: 60000 });
  await page.waitForSelector('[data-testid="app-shell"]', { timeout: 30000 });
  await page.waitForTimeout(3500);

  for (const vp of viewpoints) {
    await openViewFromBrowser(page, vp.name);
    await page.screenshot({ path: shotPath(vp.shot), fullPage: false });
  }

  // Let budget logger flush after view changes.
  await page.waitForTimeout(2800);

  const uiMeta = await page.evaluate(() => {
    const tabLabels = Array.from(document.querySelectorAll('[data-testid^="tab-activate-"]')).map(
      (el) => (el.textContent || '').trim(),
    );
    const threeDRows = Array.from(document.querySelectorAll('[data-testid="left-rail"] button, [data-testid="left-rail"] [role="button"]')).map((el) => (el.textContent || '').trim()).filter(Boolean).slice(0, 24);
    return { tabLabels, threeDRows };
  });

  const prevSummaryPath = path.join(outDir, 'summary.json');
  let previous = {};
  if (fs.existsSync(prevSummaryPath)) {
    try {
      previous = JSON.parse(fs.readFileSync(prevSummaryPath, 'utf8'));
    } catch {
      previous = {};
    }
  }

  const mergedCaptures = Array.from(new Set([...(previous.captures || []), ...captures]));
  const summary = {
    captures: mergedCaptures,
    renderingBudget: {
      debugLines: budgetDebug,
      warnLines: budgetWarn,
      latestDebugLine: budgetDebug[budgetDebug.length - 1] || null,
      latestWarnLine: budgetWarn[budgetWarn.length - 1] || null,
    },
    uiMeta,
    previousSummary: previous.summary || null,
    summary: previous.summary || null,
  };

  fs.writeFileSync(prevSummaryPath, JSON.stringify(summary, null, 2));
  await browser.close();
  console.log(JSON.stringify(summary, null, 2));
})().catch((err) => {
  console.error(err);
  process.exit(1);
});
