      />
    );
  }
  // Four-rectangle dim around the spotlight target.
  const { top, left, width, height } = rect;
  const right = left + width;
  const bottom = top + height;
  return (
    <>
      <div
        aria-hidden="true"
        style={{
          position: 'absolute',
          left: 0,
          top: 0,
          right: 0,
          height: top,
