const fs = require('fs');
const path = require('path');
const { chromium } = require('@playwright/test');

const outDir = path.resolve('tmp/ux-next-wp06-20260513');
fs.mkdirSync(outDir, { recursive: true });

async function getCounts(page) {
  return page.evaluate(() => {
    const s = window.__bimStore.getState();
    const elements = Object.values(s.elementsById || {});
    return {
      doorCount: elements.filter((e) => e && e.kind === 'door').length,
      windowCount: elements.filter((e) => e && e.kind === 'window').length,
      openingCount: elements.filter((e) => e && e.kind === 'wall_opening').length,
      selectedId: s.selectedId || null,
      activeViewpointId: s.activeViewpointId || null,
    };
  });
}

function deltaKinds(payload) {
  const out = {};
  const entries = payload?.delta?.elements || {};
  for (const el of Object.values(entries)) {
    if (!el || typeof el !== 'object') continue;
    const kind = String(el.kind || 'unknown');
    out[kind] = (out[kind] || 0) + 1;
  }
  return out;
}

(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 2048, height: 1320 } });

