  await page.waitForSelector('[data-testid="app-shell"]', { timeout: 30000 });
  const tour = page.getByTestId('onboarding-tour');
  if (await tour.isVisible().catch(() => false)) {
    await tour.getByRole('button', { name: 'Skip tour' }).click();
    await tour.waitFor({ state: 'hidden', timeout: 10000 });
  }

  await page.getByText('Target-house-3 primary front-right axonometric', { exact: true }).click();
  await page.waitForTimeout(1200);

  const before = await getCounts(page);

  const actions = [
    {
      wallId: 'hf-gf-wall-02',
      buttonId: '3d-insert-door',
      screenshot: '01-ribbon-door-wall02.png',
    },
    {
      wallId: 'hf-gf-wall-03',
      buttonId: '3d-insert-window',
      screenshot: '02-ribbon-window-wall03.png',
    },
    {
      wallId: 'hf-gf-wall-04',
      buttonId: '3d-insert-opening',
      screenshot: '03-ribbon-opening-wall04.png',
    },
  ];

  const actionResults = [];
  for (const action of actions) {
    await page.evaluate((wallId) => window.__bimStore.setState({ selectedId: wallId }), action.wallId);
    await page.click('[data-testid="ribbon-tab-modify"]');
    await page.waitForSelector(`[data-testid="${action.buttonId}"]`, { timeout: 10000 });
